det_check_template:
proof fn det_get<A, const N: usize>(self_: Array<A, N>, i: usize, r1: &A, r2: &A)
    requires (0 <= i < N), (self_.wf()),
    ensures
        ({
            &&& (*r1 == self_.seq@[i as int])
            &&& (*r2 == self_.seq@[i as int])
        }) ==> det_get_equal(r1, r2),
{
{ASSUMES}}

equal_fn_def:
// Generated equal-fn for determinism check.
// Policy: errs_equivalent=True, opaque_ok=False
spec fn det_get_equal<A>(r1: &A, r2: &A) -> bool {
    (r1 == r2)
}
